import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import Grid from '@mui/material/Unstable_Grid2';
import {GatsbyImage, getImage} from 'gatsby-plugin-image';

import Link from '@mui/material/Link';
import Divider from '@mui/material/Divider';
import * as React from 'react';
import {graphql, useStaticQuery} from 'gatsby';
import Seo from '../components/seo';
import Breadcrumbs from '@mui/material/Breadcrumbs';
import Paper from '@mui/material/Paper';
import Layout from '../components/layout';

const News = () => {

  const {
    allStrapiCorporateNew,
  } = useStaticQuery(graphql`
  query NewsQuery {
  allStrapiCorporateNew(sort: {time: DESC}) {
    nodes {
      desc
      id
      time
      title
       media {
        localFile {
        publicURL
             childImageSharp {
            gatsbyImageData
          }
        }
      }
    }

}
}`);
  const news = allStrapiCorporateNew.nodes;
  console.log(news);
  return (
      <Layout>
        <Box sx={{mt: 1}}>
          <Paper elevation={2} sx={{mr: 2, ml: 2}}>
            <Breadcrumbs sx={{pt: 2, pb: 4, pl: 2, pr: 2}}
                         aria-label="breadcrumb">
              <Link underline="hover" color="inherit" href="/">
                首页
              </Link>
              <Typography color="text.primary">新闻资讯</Typography>
            </Breadcrumbs>
            <Box sx={{flexGrow: 1, pt: 2, pb: 2, ml: 2, mr: 2}}>
              <Grid container display="flex" justifyContent="center"
                    alignItems="center" spacing={0.5}
                    columns={{xs: 4, sm: 8, md: 12}}>
                {news?.map((item, index) => {
                  return (<Box key={index}>
                    <Grid container spacing={2} >
                    <Grid md={4} xs={12}>
                      <GatsbyImage style={{maxHeight:'240px'}}
                                   image={{
                                     ...getImage(item.media[0]?.localFile),
                                     height: 400}}
                                   alt={item.title}/>
                    </Grid>
                    <Grid  spacing={2} md={8} display="flex"
                           justifyContent="start"
                           sx={{flexDirection:'column'}}
                           alignItems="center">
                      <Grid md={12} xs={12} lg={12} display="flex"
                            justifyContent="center"
                            alignItems="center">
                        <Typography variant="h5">
                          {item.title}
                        </Typography>

                      </Grid>
                      <Grid md={12} xs={12} lg={12} display="flex"
                            justifyContent="center"
                            alignItems="center">
                      <Typography variant="body2" component='div'>
                        {item.time}
                      </Typography>
                      </Grid>
                      <Grid md={12} xs={12} flexGrow={1} sx={{flexGrow:'1 !important'}}>
                        <Typography >
                          {item.desc}
                        </Typography>
                      </Grid>
                      <Grid md={12} xs={12} lg={12}  display="flex"
                            justifyContent="end"
                            alignItems="center">
                        <Link underline="hover"
                              href={`/news/${item.id}`}>阅读更多...</Link>
                      </Grid>
                    </Grid>
                    </Grid>
                    {index < news.length - 1 &&
                        <Grid sx={{mb: 2, mt: 2}} md={12}>
                          <Divider sx={{borderStyle: 'dashed'}}/></Grid>}
                  </Box>);
                })}
              </Grid>


            </Box>
          </Paper>
        </Box>
      </Layout>

  );
};

export const Head = () => <Seo title="新闻资讯"/>;
export default News;
